func newWorkflowArchiveCmd(flags *rootFlags) *cobra.Command {
	var dbPath string
	var full bool

	cmd := &cobra.Command{
		Use:   "archive",
		Short: "Sync all resources to local store for offline access and search",
		Long: `Archive fetches all syncable resources from the API and stores them in a
local SQLite database. Supports incremental sync (only new data since last run)
and full resync. After archiving, use 'search' for instant full-text search.`,
		Example: `  # Archive all resources
  clickup-pp-cli workflow archive

  # Full re-archive (ignore previous sync state)
  clickup-pp-cli workflow archive --full`,
		RunE: func(cmd *cobra.Command, args []string) error {
			c, err := flags.newClient()
			if err != nil {
				return err
			}
			c.NoCache = true

			if dbPath == "" {
				dbPath = defaultDBPath("clickup-pp-cli")
			}
			db, err := store.OpenWithContext(cmd.Context(), dbPath)
			if err != nil {
				return fmt.Errorf("opening store: %w", err)
			}
			defer db.Close()

			// PATCH(pp-library#433-p1): archive every default resource through
			// the shared syncResource engine instead of a private team+user
			// fetch loop. The old loop (a) listed only `team` and `user` while
			// this command advertises "all syncable resources", so `workflow
			// archive` followed by `search` for tasks/spaces/docs returned
			// nothing, and (b) paginated v2 list endpoints with a `?after=<id>`
			// cursor ClickUp ignores — an account with exactly 100 workspaces
			// never satisfied the `len(items) < 100` break and re-fetched page
			// one forever. syncResource already implements per-resource
			// pagination (v2 page-number vs v3 cursor) and hierarchical
			// parent-first traversal, so archive now honors its contract.
			resources := defaultSyncResources()
			if hasHierarchicalResource(resources) {
				// Hierarchical resources (space → folder → list → task, etc.)
				// must be walked parent-first; run them in dependency order.
				resources = orderResourcesByDependency(resources)
			}

			totalSynced := 0
			syncedResources := 0
			for _, resource := range resources {
				fmt.Fprintf(cmd.ErrOrStderr(), "Syncing %s...\n", resource)
				// maxPages 100 matches the `sync` command's default cap.
				res := syncResource(c, db, resource, "", full, false, 100)
				switch {
				case res.Err != nil:
					fmt.Fprintf(cmd.ErrOrStderr(), "  warning: %s: %v\n", resource, res.Err)
				case res.Warn != nil:
					fmt.Fprintf(cmd.ErrOrStderr(), "  warning: %s: %v\n", resource, res.Warn)
				default:
					syncedResources++
					totalSynced += res.Count
					fmt.Fprintf(cmd.ErrOrStderr(), "  %s: %d items\n", resource, res.Count)
				}
			}

			if flags.asJSON {
				enc := json.NewEncoder(cmd.OutOrStdout())
				enc.SetIndent("", "  ")
				return enc.Encode(map[string]any{
					"resources_synced": syncedResources,
					"total_items":      totalSynced,
					"store_path":       dbPath,
					"timestamp":        time.Now().UTC().Format(time.RFC3339),
				})
			}

			fmt.Fprintf(cmd.OutOrStdout(), "Archived %d items across %d resources to %s\n", totalSynced, syncedResources, dbPath)
			return nil
		},
	}

	cmd.Flags().StringVar(&dbPath, "db", "", "Database path (default: ~/.local/share/clickup-pp-cli/data.db)")
	cmd.Flags().BoolVar(&full, "full", false, "Full re-archive (ignore previous sync state)")

	return cmd
}

func newWorkflowStatusCmd(flags *rootFlags) *cobra.Command {
	var dbPath string

	cmd := &cobra.Command{
		Use:         "status",
		Short:       "Show local archive status and sync state for all resources",
		Annotations: map[string]string{"mcp:read-only": "true"},
		Example: `  # Show archive status
  clickup-pp-cli workflow status

  # Show status as JSON
  clickup-pp-cli workflow status --json`,
		RunE: func(cmd *cobra.Command, args []string) error {
			if dbPath == "" {
				dbPath = defaultDBPath("clickup-pp-cli")
			}
			s, err := store.OpenWithContext(cmd.Context(), dbPath)
			if err != nil {
				return fmt.Errorf("opening store: %w", err)
			}
			defer s.Close()

			status, err := s.Status()
			if err != nil {
				return err
			}

			if flags.asJSON {
				enc := json.NewEncoder(cmd.OutOrStdout())
				enc.SetIndent("", "  ")
				return enc.Encode(status)
			}

			if len(status) == 0 {
				fmt.Fprintln(cmd.OutOrStdout(), "No archived data. Run 'workflow archive' to sync.")
				return nil
			}

			fmt.Fprintln(cmd.OutOrStdout(), "Archive Status:")
			total := 0
			for resource, count := range status {
				fmt.Fprintf(cmd.OutOrStdout(), "  %-30s %d items\n", resource, count)
				total += count
			}
			fmt.Fprintf(cmd.OutOrStdout(), "\n  Total: %d items\n", total)
			fmt.Fprintf(cmd.OutOrStdout(), "  Store: %s\n", dbPath)
			return nil
		},
	}

	cmd.Flags().StringVar(&dbPath, "db", "", "Database path")

	return cmd
}

